/**
 * sw-register.js — Service Worker registration
 *
 * Import this in main.jsx to enable PWA install + offline fallback:
 *   import './sw-register';
 *
 * The service worker itself (sw.js) is generated by vite-plugin-pwa.
 * Until that plugin is installed, this script registers a minimal
 * cache-first service worker for the app shell.
 */

if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker
      .register('/sw.js', { scope: '/' })
      .then((reg) => {
        console.log('[SW] Registered, scope:', reg.scope);

        // Detect new SW version available
        reg.addEventListener('updatefound', () => {
          const newWorker = reg.installing;
          newWorker?.addEventListener('statechange', () => {
            if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
              // New version is ready — prompt rider to refresh
              console.log('[SW] New version available. Notifying app…');
              window.dispatchEvent(new CustomEvent('sw:update-available'));
            }
          });
        });
      })
      .catch((err) => {
        console.warn('[SW] Registration failed:', err);
      });

    // Listen for new SW controlling the page (after skip waiting)
    navigator.serviceWorker.addEventListener('controllerchange', () => {
      console.log('[SW] Controller changed — reloading for fresh assets');
      window.location.reload();
    });
  });
}
